    "lyricsHtml": "\n<span class=\"chord\" data-chord=\"C7(4/9)\">C7(4/9)</span>      <span class=\"chord\" data-chord=\"C7(9)\">C7(9)</span>\n<span class=\"lyric-line\"> Lá no avarandado</span>\n<span class=\"chord\" data-chord=\"C7(4/9)\">C7(4/9)</span>        <span class=\"chord\" data-chord=\"C7(9)\">C7(9)</span> <span class=\"chord\" data-chord=\"F7M\">F7M</span>\n<span class=\"lyric-line\">Na luz do meio dia</span>\n    <span class=\"chord\" data-chord=\"Fm6\">Fm6</span>            <span class=\"chord\" data-chord=\"Em7\">Em7</span> <span class=\"chord\" data-chord=\"Am7\">Am7</span>  <span class=\"chord\" data-chord=\"Dm7\">Dm7</span>\n<span class=\"lyric-line\">O segredo dos teus olhos</span>\n      <span class=\"chord\" data-chord=\"G7(4/9)\">G7(4/9)</span>    <span class=\"chord\" data-chord=\"C6(9)\">C6(9)</span>\n<span class=\"lyric-line\">Tanta coisa me dizia</span>\n<span class=\"chord\" data-chord=\"C7(4/9)\">C7(4/9)</span>              <span class=\"chord\" data-chord=\"C7(9)\">C7(9)</span>\n<span class=\"lyric-line\"> O cabelo solto ao vento</span>\n<span class=\"chord\" data-chord=\"C7(4/9)\">C7(4/9)</span>         <span class=\"chord\" data-chord=\"C7(9)\">C7(9)</span> <span class=\"chord\" data-chord=\"F7M\">F7M</span>\n<span class=\"lyric-line\"> O teu jeito de olhar</span>\n     <span class=\"chord\" data-chord=\"Fm6\">Fm6</span>         <span class=\"chord\" data-chord=\"Em7\">Em7</span> <span class=\"chord\" data-chord=\"Am7\">Am7</span>  <span class=\"chord\" data-chord=\"Dm7\">Dm7</span>\n<span class=\"lyric-line\">E no seu corpo moreno</span>\n       <span class=\"chord\" data-chord=\"G7(4/9)\">G7(4/9)</span>  <span class=\"chord\" data-chord=\"C6(9)\">C6(9)</span>\n<span class=\"lyric-line\">A flor de maracujá</span>\n<span class=\"chord\" data-chord=\"F6\">F6</span>          <span class=\"chord\" data-chord=\"Eb7M\">Eb7M</span>\n<span class=\"lyric-line\">Dia de sol, cheiro de flor</span>\n<span class=\"chord\" data-chord=\"Bb7M\">Bb7M</span>           <span class=\"chord\" data-chord=\"C7M\">C7M</span>\n<span class=\"lyric-line\">Gosto de mar, amor</span>\n<span class=\"chord\" data-chord=\"F6\">F6</span>          <span class=\"chord\" data-chord=\"Eb7M\">Eb7M</span>\n<span class=\"lyric-line\">Na tua cor, luz do luar</span>\n<span class=\"chord\" data-chord=\"Bb7M\">Bb7M</span>             <span class=\"chord\" data-chord=\"G7(4/9)\">G7(4/9)</span>\n<span class=\"lyric-line\">Vento que vem do mar</span>\n<span class=\"chord\" data-chord=\"C7(4/9)\">C7(4/9)</span>           <span class=\"chord\" data-chord=\"C7(9)\">C7(9)</span> <span class=\"chord\" data-chord=\"C7(4/9)\">C7(4/9)</span>\n<span class=\"lyric-line\">Roda, gira vira o vento</span>\n                  <span class=\"chord\" data-chord=\"C7(9)\">C7(9)</span> <span class=\"chord\" data-chord=\"F7M\">F7M</span>\n<span class=\"lyric-line\">Meu amor vai te levar</span>\n        <span class=\"chord\" data-chord=\"Fm6\">Fm6</span>          <span class=\"chord\" data-chord=\"Em7\">Em7</span> <span class=\"chord\" data-chord=\"Am7\">Am7</span>  <span class=\"chord\" data-chord=\"Dm7\">Dm7</span>\n<span class=\"lyric-line\">Bem pra lá do fim do mundo</span>\n     <span class=\"chord\" data-chord=\"G7(4/9)\">G7(4/9)</span>      <span class=\"chord\" data-chord=\"C6(9)\">C6(9)</span>\n<span class=\"lyric-line\">Onde eu vou te chamar</span>\n",
